create or replace function gmdb.merge_details(dest jsonb, source jsonb)
    returns jsonb
    language plpgsql
    immutable
as $$
declare mergedResources jsonb;
begin
    mergedResources := coalesce(dest->'resources', '{}'::jsonb) ||
                       coalesce(source->'resources', '{}'::jsonb);

    return  coalesce(dest - 'resources', '{}'::jsonb) ||
            coalesce(source - 'resources', '{}'::jsonb) ||
            case
                when mergedResources = '{}'::jsonb then '{}'::jsonb
                else jsonb_build_object('resources', mergedResources)
            end;
end;
$$;
